/**
 * 减弱动态效果
 * https://developer.mozilla.org/en-US/docs/Web/CSS/@media/prefers-reduced-motion
 */
import * as React from 'react';
import { useMedia } from '../hooks';
import { createGlobalConfig } from '@universe-design/react-provider';

const { ConfigProvider, useConfig } = /* #__PURE__*/ createGlobalConfig<boolean>('reduced-motion', false);

const PrefersReducedMotion = '(prefers-reduced-motion)';

export const Unstable_ConfigReducedMotion = ({
  value,
  children,
}: React.PropsWithChildren<{
  /**
   * 是否减弱动态效果
   * - true， 减弱动态效果
   * - false, 正常动态效果
   * - `follow-system`, 跟随系统
   */
  value: boolean | 'follow-system';
}>) => {
  const systemReducedMotion = useMedia(PrefersReducedMotion, {
    skipped: value !== 'follow-system',
  });
  return <ConfigProvider value={value === 'follow-system' ? systemReducedMotion : value}>{children}</ConfigProvider>;
};

export const unstable_useConfigReducedMotion = useConfig;
